<Stats id="monster-ape_megaprimatus--stats" atts={[29,15,22,2,12,15]} bab={7} cmb={20} cmd={32} feats={["Combat Reflexes","Iron Will",["Skill Focus"," (Perception)"],"Snatch",["Weapon Focus"," (slam)"]]} skills={{"acro":{"b":10},"climb":{"b":21},"per":{"b":11}}} />
