<Offense id="monster-archon_hammer_archon--offense" sp={30} fl={90} flP="good" melee="+4 impact lucerne hammer +30/+25/+20/+15 (4d6+13)" space={"10"} reach={"10"} reachP={"15 ft. with lucerne hammer"} specAtt={[["axiomatic barrage","axiomatic barrage"],["inevitable sunder","inevitable sunder"]]} />
